         Probability = prediction.Probability,
         Score = prediction.Score,
     });
 });

 app.Run();

 static void TrainModel(string csvPath, string modelPath)
 {
     var mlContext = new MLContext(seed: 42);

     var rawData = mlContext.Data.LoadFromTextFile<CustomerCsvRow>(csvPath, hasHeader: true, separatorChar: ',');

     // Preprocess: convert "Yes"/"No" to a boolean Label column before building the model pipeline.
     // This keeps the saved model independent of the Churned column so predictions work with CustomerInput.
     var labelMap = new List<KeyValuePair<string, bool>> { new("Yes", true), new("No", false) };
     var labelTransform = mlContext.Transforms.Conversion.MapValue("Label", labelMap, inputColumnName: "Churned");
     var labeledData = labelTransform.Fit(rawData).Transform(rawData);

     // Model pipeline operates only on columns present in CustomerInput + the Label
     var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerInput.Region))
         .Append(mlContext.Transforms.Concatenate("Features",
             nameof(CustomerInput.Age),
             nameof(CustomerInput.Income),
             nameof(CustomerInput.PurchaseHistory),
             "RegionEncoded"))
         .Append(mlContext.Transforms.NormalizeMinMax("Features"))
         .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

     long rowCount = labeledData.GetColumn<float>("Age").Count();

     ITransformer model;
     if (rowCount >= 20)
     {
         var split = mlContext.Data.TrainTestSplit(labeledData, testFraction: 0.2, seed: 42);
         model = pipeline.Fit(split.TrainSet);

         var predictions = model.Transform(split.TestSet);
         var metrics = mlContext.BinaryClassification.Evaluate(predictions);
         Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
     }
     else
     {
         Console.WriteLine($"Small dataset ({rowCount} rows) — training on all data. Add more rows for train/test evaluation.");
         model = pipeline.Fit(labeledData);
     }

     // Save using the schema that matches CustomerInput (no Churned column)
     var inputSchema = mlContext.Data.LoadFromEnumerable(Array.Empty<CustomerInput>()).Schema;
     mlContext.Model.Save(model, inputSchema, modelPath);
     Console.WriteLine($"Model saved to {modelPath}");
 }

